func (s *Service) GetAvailableHandsets(ctx context.Context, customerID, serviceID string) ([]models.Handset, error) {
	if serviceID == "" {
		return nil, fmt.Errorf("service_id is required: %w", terrors.ErrBadRequest)
	}

