// MobileAvailableHandsets is the resolver for the mobileAvailableHandsets field.
func (r *queryResolver) MobileAvailableHandsets(ctx context.Context, serviceID string, includeOutOfStock *bool) ([]*sharedmodel.MobileHandsetBrand, error) {
	customerAuth, err := r.authorize(ctx, cerbos.GET_AVAILABLE_HANDSETS)
	if err != nil {
		return nil, err
	}

	resp, err := r.HandsetApiClient.GetAvailableHandsets(ctx, &handsetpb.GetAvailableHandsetsRequest{
		ServiceId:  serviceID,
		CustomerId: customerAuth.AccountNumber,
	})
	if err != nil {
		return nil, err
	}

	showOutOfStock := includeOutOfStock != nil && *includeOutOfStock

	type modelKey struct{ manufacturer, model string }
	type modelData struct {
		handsets []*handsetpb.Handset
	}

	brandOrder := []string{}
	brandModels := map[string][]string{}
	modelHandsets := map[modelKey]*modelData{}

	for _, h := range resp.GetHandsets() {
		if !showOutOfStock && h.GetOutOfStock() {
			continue
		}
		mk := modelKey{h.GetManufacturer(), h.GetModel()}
		if _, exists := modelHandsets[mk]; !exists {
			if _, brandExists := modelHandsets[modelKey{h.GetManufacturer(), ""}]; !brandExists {
				brandOrder = append(brandOrder, h.GetManufacturer())
			}
			brandModels[h.GetManufacturer()] = append(brandModels[h.GetManufacturer()], h.GetModel())
			modelHandsets[mk] = &modelData{}
		}
		modelHandsets[mk].handsets = append(modelHandsets[mk].handsets, h)
	}

	sort.Strings(brandOrder)

	var brands []*sharedmodel.MobileHandsetBrand
	for _, brandName := range brandOrder {
		models := brandModels[brandName]
		sort.Strings(models)

		var phones []*sharedmodel.MobileHandsetPhone
		for _, modelName := range models {
			mk := modelKey{brandName, modelName}
			data := modelHandsets[mk]

			colourSeen := map[string]bool{}
			storageSeen := map[string]bool{}
			var colours, storages []string
			var variants []*sharedmodel.MobileHandsetVariant
			var fromPricePence int32

			for _, h := range data.handsets {
				if !colourSeen[h.GetColours()] {
					colourSeen[h.GetColours()] = true
					colours = append(colours, h.GetColours())
				}
				if !storageSeen[h.GetCapacity()] {
					storageSeen[h.GetCapacity()] = true
					storages = append(storages, h.GetCapacity())
				}

				rentalPence := h.GetRentalPrice().GetAmount()
				pence, _ := parsePenceFromMoney(rentalPence)
				if fromPricePence == 0 || pence < fromPricePence {
					fromPricePence = pence
				}

				variants = append(variants, &sharedmodel.MobileHandsetVariant{
					ID: h.GetId(),
					Attributes: []*sharedmodel.MobileHandsetAttribute{
