func (s *Service) GetAvailableHandsets(ctx context.Context, customerID, serviceID string) ([]models.Handset, error) {
	if serviceID == "" {
		return nil, fmt.Errorf("service_id is required: %w", terrors.ErrBadRequest)
	}

	// If the customer already has an active contract on this service, return empty list
	_, err := s.store.GetActiveContractForService(ctx, serviceID)
	if err == nil {
		tlog.WithAttribute("service_id", serviceID).
			Info(ctx, "active contract exists, returning empty handset list")
		return nil, nil
	}
	if !errors.Is(err, terrors.ErrNotFound) {
		return nil, fmt.Errorf("failed to check active contract: %w", err)
	}

	err = s.checkPreEligibility(ctx, customerID)
	if err != nil {
		return nil, fmt.Errorf("failed pre-eligibility checks: %w", err)
	}

	handsets, err := s.store.GetHandsets(ctx, true)
	if err != nil {
		return nil, fmt.Errorf("failed to get handsets: %w", err)
	}

