syntax = "proto3";
package handset;

option go_package = "github.com/utilitywarehouse/telecom-mobile/services/handset/pkg/protos/generated/v1/apis/handset";

import "google/api/annotations.proto";
import "protoc-gen-openapiv2/options/annotations.proto";
import "mobile/v1/events/service_events.proto";
import "google/protobuf/empty.proto";
import "google/protobuf/timestamp.proto";

option (grpc.gateway.protoc_gen_openapiv2.options.openapiv2_swagger) = {
  info: {
    title: "Handset API"
    version: "1.0.0"
    contact: {
      name: "telecom"
      url: "https://github.com/utilitywarehouse/telecom-mobile"
      email: "telecom@uw.co.uk"
    }
  };
}
;

service HandsetAPI {
  rpc GetActiveContractForService(GetActiveContractForServiceRequest)
      returns (GetActiveContractForServiceResponse) {
    option (grpc.gateway.protoc_gen_openapiv2.options.openapiv2_operation) = {
      description: "gets existing handset contract for a given service"
    };
    option (google.api.http) = {
      get: "/v1/handsets/contracts"
    };
  }
  rpc GetAvailableHandsets(GetAvailableHandsetsRequest)
      returns (GetAvailableHandsetsResponse) {
    option (grpc.gateway.protoc_gen_openapiv2.options.openapiv2_operation) = {
      description: "gets available handsets for order for a given service"
    };
    option (google.api.http) = {
      get: "/v1/handsets/available"
    };
  }
  rpc RequestHandsetForService(RequestHandsetForServiceRequest)
      returns (RequestHandsetForServiceResponse) {
    option (grpc.gateway.protoc_gen_openapiv2.options.openapiv2_operation) = {
      description: "requests a handset for a given service"
    };
    option (google.api.http) = {
      post: "/v1/handsets/requests"
      body: "*"
    };
  }
  rpc EligibilityCallbackSuccess(EligibilityCallbackSuccessRequest)
      returns (google.protobuf.Empty) {
    option (grpc.gateway.protoc_gen_openapiv2.options.openapiv2_operation) = {
      description: "callback endpoint for handset eligibility success response from external provider"
    };
    option (google.api.http) = {
      post: "/v1/handsets/eligibility/completed"
      body: "*"
    };
  }
  rpc EligibilityCallbackFailure(EligibilityCallbackFailureRequest)
      returns (google.protobuf.Empty) {
    option (grpc.gateway.protoc_gen_openapiv2.options.openapiv2_operation) = {
