sort.Strings(brandOrder)

var brands []*sharedmodel.MobileHandsetBrand
for _, brandName := range brandOrder {
	models := brandModels[brandName]
	sort.Strings(models)

	var phones []*sharedmodel.MobileHandsetPhone
	for _, modelName := range models {
		mk := modelKey{brandName, modelName}
		data := modelHandsets[mk]

		colourSeen := map[string]bool{}
		storageSeen := map[string]bool{}
		var colours, storages []string
		var variants []*sharedmodel.MobileHandsetVariant
		var fromPricePence int32

		for _, h := range data.handsets {
			if !colourSeen[h.GetColours()] {
				colourSeen[h.GetColours()] = true
				colours = append(colours, h.GetColours())
			}
			if !storageSeen[h.GetCapacity()] {
				storageSeen[h.GetCapacity()] = true
				storages = append(storages, h.GetCapacity())
			}

			rentalPence := h.GetRentalPrice().GetAmount()
			pence, _ := parsePenceFromMoney(rentalPence)
			if fromPricePence == 0 || pence < fromPricePence {
				fromPricePence = pence
			}

			variants = append(variants, &sharedmodel.MobileHandsetVariant{
				ID: h.GetId(),
				Attributes: []*sharedmodel.MobileHandsetAttribute{
					{Key: "colour", Value: h.GetColours()},
					{Key: "storage", Value: h.GetCapacity()},
				},
				MonthlyCharge: &sharedmodel.MobileMoney{
					Amount:   h.GetRentalPrice().GetAmount(),
					Currency: h.GetRentalPrice().GetCurrency(),
				},
				Rrp: &sharedmodel.MobileMoney{
					Amount:   h.GetRrp().GetAmount(),
					Currency: h.GetRrp().GetCurrency(),
				},
				InStock: h.GetInStock(),
			})
		}

		first := data.handsets[0]
		optionTypes := []*sharedmodel.MobileHandsetOptionType{
			{Key: "colour", Values: colours},
			{Key: "storage", Values: storages},
		}

		phones = append(phones, &sharedmodel.MobileHandsetPhone{
			Model: modelName,
			FromPrice: &sharedmodel.MobileMoney{
				Amount:   fmt.Sprintf("%.2f", float64(fromPricePence)/100),
				Currency: "GBP",
			},
			ScreenSize:         first.GetScreenSize(),
			Battery:            first.GetBattery(),
			WiFiStandard:       first.GetWifiStandard(),
			ESim:               first.GetEsim(),
			DualSim:            first.GetDualSim(),
			SpecificationsLink: first.GetSpecificationsLink(),
			OptionTypes:        optionTypes,
			Variants:           variants,
		})
	}

	if len(phones) > 0 {
		brands = append(brands, &sharedmodel.MobileHandsetBrand{
			Name:   brandName,
			Phones: phones,

